#!/usr/bin/env python3
"""Temporary deterministic writer for the hybrid retrieval conformance vector."""
from __future__ import annotations

import base64
import gzip
import json
from pathlib import Path

ROOT = Path(__file__).resolve().parents[1]
TARGET = ROOT / "conformance" / "hybrid_memory_retrieval_vectors.json"
PAYLOAD = """"""


def main() -> None:
    payload = gzip.decompress(base64.b64decode(PAYLOAD))
    document = json.loads(payload.decode("utf-8"))
    TARGET.write_text(json.dumps(document, ensure_ascii=False, indent=2) + "\n", encoding="utf-8", newline="\n")
    print(f"Generated {TARGET.relative_to(ROOT)}")


if __name__ == "__main__":
    main()
